import React, { useMemo } from 'react';
import { useLocation } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import {
  defaultDescription,
  defaultTitle,
  getCanonicalUrl,
  getDefaultMetaGroups,
  getDefaultOgImageUrl,
  getSiteUrl,
  siteName
} from '../utils/seo';

/**
 * Global Helmet defaults: title fallback, description, canonical, Open Graph, Twitter, theme-color.
 * Per-route <Helmet> on pages overrides matching tags.
 */
export default function GlobalSeo() {
  const { pathname } = useLocation();
  const isAdmin = pathname.startsWith('/admin');
  const isAccount = pathname.startsWith('/account');
  const isAuthArea =
    pathname === '/login' ||
    pathname === '/register' ||
    pathname.startsWith('/forgot-password') ||
    pathname.startsWith('/reset-password') ||
    pathname.startsWith('/verify-email/');
  const isTransactional =
    /^\/(cart|checkout|orders)($|\/)/.test(pathname) || pathname.startsWith('/order-confirmation/');
  const noindex = isAdmin || isAccount || isAuthArea || isTransactional;

  const canonical = useMemo(() => getCanonicalUrl(pathname), [pathname]);
  const groups = useMemo(() => getDefaultMetaGroups(pathname), [pathname]);
  const absoluteOgImage = getDefaultOgImageUrl();
  const site = getSiteUrl() || (typeof window !== 'undefined' ? window.location.origin : '');

  const orgJsonLd = useMemo(() => {
    if (pathname !== '/' && pathname !== '') return null;
    return {
      '@context': 'https://schema.org',
      '@type': 'Organization',
      name: siteName,
      url: site || canonical,
      logo: site ? `${site}/favicon.ico` : undefined
    };
  }, [canonical, pathname, site]);

  return (
    <Helmet
      defaultTitle={defaultTitle}
      htmlAttributes={{ lang: 'en' }}
    >
      <meta name="description" content={defaultDescription} />
      {noindex ? (
        <meta name="robots" content="noindex, nofollow" />
      ) : (
        <meta name="robots" content="index, follow, max-image-preview:large, max-snippet:-1" />
      )}
      <link rel="canonical" href={canonical} />
      <meta name="theme-color" content="#0f0f1a" />

      <meta property="og:site_name" content={siteName} />
      <meta property="og:locale" content={groups.og.locale} />
      <meta property="og:type" content={groups.og.type} />
      <meta property="og:title" content={groups.og.title} />
      <meta property="og:description" content={groups.og.description} />
      <meta property="og:url" content={groups.og.url} />
      <meta property="og:image" content={absoluteOgImage} />
      <meta property="og:image:width" content="1200" />
      <meta property="og:image:height" content="630" />
      <meta property="og:image:alt" content={siteName} />

      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={groups.twitter.title} />
      <meta name="twitter:description" content={groups.twitter.description} />
      <meta name="twitter:image" content={absoluteOgImage} />

      {orgJsonLd && (
        <script type="application/ld+json">{JSON.stringify(orgJsonLd)}</script>
      )}
    </Helmet>
  );
}
